<?php
namespace App\Domain\Inventory\Instances;
use App\Domain\Equipment\CharacterEquipmentSlot;use App\Models\Character;use App\Models\Item;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\ShopSale;use Carbon\CarbonImmutable;use Illuminate\Support\Facades\DB;use RuntimeException;
final class ItemInstanceEventService{public function appendEquipped(ItemInstance $instance,Character $actor,Item $item,$slot,$operationUuid,CarbonImmutable $now,array $metadata=[]){return$this->append($instance,$actor,$item,$slot,$operationUuid,$now,ItemInstanceEventType::EQUIPPED,$metadata);}public function appendUnequipped(ItemInstance $instance,Character $actor,Item $item,$slot,$operationUuid,CarbonImmutable $now,array $metadata=[]){return$this->append($instance,$actor,$item,$slot,$operationUuid,$now,ItemInstanceEventType::UNEQUIPPED,$metadata);}public function appendRefinementSucceeded(ItemInstance $instance,Character $actor,Item $item,$operationUuid,array $metadata,CarbonImmutable $now){return$this->appendRefinementResult($instance,$actor,$item,$operationUuid,$metadata,$now,ItemInstanceEventType::REFINEMENT_SUCCEEDED);}public function appendRefinementFailed(ItemInstance $instance,Character $actor,Item $item,$operationUuid,array $metadata,CarbonImmutable $now){return$this->appendRefinementResult($instance,$actor,$item,$operationUuid,$metadata,$now,ItemInstanceEventType::REFINEMENT_FAILED);}public function appendSoldToShop(ItemInstance $instance,Character $actor,ShopSale $sale,array $metadata,CarbonImmutable $now){if(DB::transactionLevel()<1)throw new RuntimeException('Active transaction required.');if((int)$instance->character_id!==(int)$actor->id||(int)$sale->character_id!==(int)$actor->id||(int)$sale->item_instance_id!==(int)$instance->id)throw new RuntimeException('Invalid Shop sale event context.');return ItemInstanceEvent::create(['item_instance_id'=>$instance->id,'operation_uuid'=>$sale->idempotency_key,'event_type'=>ItemInstanceEventType::SOLD_TO_SHOP,'actor_character_id'=>$actor->id,'from_character_id'=>$actor->id,'to_character_id'=>null,'from_item_id'=>$instance->item_id,'to_item_id'=>$instance->item_id,'refinement_before'=>$instance->refinement_level,'refinement_after'=>$instance->refinement_level,'source_type'=>'shop_sale','source_id'=>$sale->id,'metadata'=>$metadata,'occurred_at'=>$now,'created_at'=>$now]);}private function appendRefinementResult(ItemInstance $instance,Character $actor,Item $item,$operationUuid,array $metadata,CarbonImmutable $now,$type){if(DB::transactionLevel()<1)throw new RuntimeException('Active transaction required.');return ItemInstanceEvent::create(['item_instance_id'=>$instance->id,'operation_uuid'=>$operationUuid,'event_type'=>$type,'actor_character_id'=>$actor->id,'from_character_id'=>$actor->id,'to_character_id'=>$actor->id,'from_item_id'=>$item->id,'to_item_id'=>$item->id,'refinement_before'=>$metadata['from_level'],'refinement_after'=>$metadata['current_level'],'source_type'=>'refinement_level','source_id'=>$metadata['refinement_rule_id'],'metadata'=>$metadata,'occurred_at'=>$now,'created_at'=>$now]);}private function append(ItemInstance $instance,Character $actor,Item $item,$slot,$operationUuid,CarbonImmutable $now,$type,array $metadata){if(DB::transactionLevel()<1)throw new RuntimeException('Active transaction required.');CharacterEquipmentSlot::assertValid($slot);if((int)$instance->character_id!==(int)$actor->id||(int)$instance->item_id!==(int)$item->id)throw new RuntimeException('Invalid equipment event context.');return ItemInstanceEvent::create(['item_instance_id'=>$instance->id,'operation_uuid'=>$operationUuid,'event_type'=>$type,'actor_character_id'=>$actor->id,'from_character_id'=>$actor->id,'to_character_id'=>$actor->id,'from_item_id'=>$item->id,'to_item_id'=>$item->id,'refinement_before'=>$instance->refinement_level,'refinement_after'=>$instance->refinement_level,'source_type'=>null,'source_id'=>null,'metadata'=>array_merge(['slot'=>$slot],$metadata),'occurred_at'=>$now,'created_at'=>$now]);}}
